// Import necessary dependencies
import org.elasticsearch.client.RestClient;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentBuilder;
import org.elasticsearch.common.xcontent.XContentFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

// Create a configuration class for Elasticsearch connection
@Configuration
public class ElasticsearchConfig {
    
    @Value("${elasticsearch.url}")
    private String esUrl;
    
    @Value("${elasticsearch.port}")
    private int esPort;
    
    @Bean
    public RestHighLevelClient getElasticsearchClient() throws Exception {
        RestClient restClient = RestClient.builder(new HttpHost(esUrl, esPort)).build();
        return new RestHighLevelClient(restClient);
    }
}

// Create a service class for product indexing and search
@Service
public class ProductSearchService {
    
    @Autowired
    private RestHighLevelClient elasticsearchClient;
    
    public void indexProduct(Product product) throws Exception {
        XContentBuilder builder = XContentFactory.jsonBuilder()
                .startObject()
                    .field("id", product.getId())
                    .field("name", product.getName())
                    .field("description", product.getDescription())
                    .field("price", product.getPrice())
                .endObject();
        
        IndexRequest request = new IndexRequest("products")
                .source(builder)
                .id(product.getId().toString());
        
        elasticsearchClient.index(request);
    }
    
    public SearchResponse searchProducts(String query) throws Exception {
        SearchSourceBuilder builder = new SearchSourceBuilder()
                .query(QueryBuilders.queryStringQuery(query));
        
        SearchRequest request = new SearchRequest("products")
                .source(builder);
        
        SearchResponse response = elasticsearchClient.search(request);
        
        return response;
    }
    
    public FacetsResult getFacets() throws Exception {
        SearchSourceBuilder builder = new SearchSourceBuilder();
        
        SearchRequest request = new SearchRequest("products")
                .source(builder);
        
        SearchResponse response = elasticsearchClient.search(request);
        
        Aggregations aggregations = response.getAggregations();
        return (FacetsResult) aggregations.get("categories").getBucket(0).getValue();
    }
}

